// Pastikan Luxon tersedia atau gunakan cara ini di n8n Code Node
const items = $input.all(); 

for (let item of items) {
  // 1. Ambil data biner
  const binaryData = item.binary?.Upload_CV__PDF_;

  if (binaryData) {
    // Memindahkan data biner ke JSON (Base64)
    item.json.cv_base64 = binaryData.data; 
    item.json.fileName = binaryData.fileName;
  }

  // 2. Tambahkan tanggal format Indonesia
  // Di n8n modern, Anda bisa menggunakan $now atau Luxon bawaan
  item.json.tanggal_input = new Date().toLocaleString('id-ID', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  }).replace(/\//g, '-').replace(',', '');
}

return items;

const items = $input.all();

for (let item of items) {
  const aiResponseText = item.json.text; // Output teks dari LLM

  try {
    // 1. Bersihkan formatting jika AI memberikan markdown ```json ... ```
    const cleanJson = aiResponseText.replace(/```json|```/g, '').trim();

    // 2. Parse string menjadi Objek
    const parsedData = JSON.parse(cleanJson);

    // 3. Masukkan ke item.json agar bisa dipanggil node selanjutnya
    item.json.ai_name = parsedData.candidate_name;
    item.json.ai_exp = parsedData.years_of_experience;
    item.json.ai_skills = parsedData.top_skills.join(", "); // Array jadi string
    item.json.ai_summary = parsedData.summary;
    item.json.ai_score = parsedData.score;
    item.json.ai_rec = parsedData.hiring_recommendation;

  } catch (error) {
    // Fallback jika AI gagal generate JSON valid
    item.json.error = "Gagal parsing JSON dari AI";
    item.json.raw_output = aiResponseText;
  }
}

return items;
